package com.oneil.wellness.walkplanner.controller;import com.oneil.wellness.walkplanner.data.*;import com.oneil.wellness.walkplanner.goal.*;import java.time.LocalDate;import java.util.Map;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/api")public class DataController{private final WellnessGoalService goals;private final HistoryRetentionService retention;private final DataDeletionService deletion;private final HistoryExportService exports;public DataController(WellnessGoalService g,HistoryRetentionService r,DataDeletionService d,HistoryExportService e){goals=g;retention=r;deletion=d;exports=e;}@GetMapping("/settings/wellness-goals")public WellnessGoal goals(){return goals.current();}@PutMapping("/settings/wellness-goals")public WellnessGoal goals(@RequestBody WellnessGoalRequest r){return goals.save(r);}@GetMapping("/settings/wellness-goals/progress")public GoalProgress progress(){return goals.progress();}@GetMapping("/settings/history-retention")public HistoryRetention retention(){return retention.current();}@PutMapping("/settings/history-retention")public HistoryRetention retention(@RequestBody HistoryRetentionRequest r){return retention.save(r);}@DeleteMapping("/history/recommendations")public Map<String,Long> recommendations(@RequestParam LocalDate from,@RequestParam LocalDate to,@RequestParam(defaultValue="UTC")String timezone){return Map.of("deleted",deletion.recommendations(from,to,timezone));}@DeleteMapping("/history/notifications")public Map<String,Long> notifications(){return Map.of("deleted",deletion.notifications());}@DeleteMapping("/history/activities")public Map<String,Long> activities(){return Map.of("deleted",deletion.activities());}@DeleteMapping("/history/all")public Map<String,Long> all(){return deletion.all();}@GetMapping("/history/export/activities.csv")public ResponseEntity<byte[]> activitiesCsv(){return file(exports.activitiesCsv(),"text/csv","wellness-window-activities.csv");}@GetMapping("/history/export/recommendations.csv")public ResponseEntity<byte[]> recommendationsCsv(){return file(exports.recommendationsCsv(),"text/csv","wellness-window-recommendations.csv");}@GetMapping("/history/export/daily-summary.csv")public ResponseEntity<byte[]> dailyCsv(){return file(exports.dailyCsv(),"text/csv","wellness-window-daily-summary.csv");}@GetMapping("/history/export/all.json")public ResponseEntity<byte[]> allJson(@RequestParam(defaultValue="UTC")String timezone){return file(exports.allJson(timezone),"application/json","wellness-window-history.json");}private ResponseEntity<byte[]> file(byte[] bytes,String type,String name){return ResponseEntity.ok().header(HttpHeaders.CONTENT_TYPE,type+"; charset=UTF-8").header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=\""+name+"\"").header(HttpHeaders.CACHE_CONTROL,"no-store").body(bytes);}}
